+        ...req,
+        apiKey,
+        baseUrl: normalizeMistralRealtimeBaseUrl(config.baseUrl),
+        model: config.model ?? MISTRAL_REALTIME_DEFAULT_MODEL,
+        sampleRate: config.sampleRate ?? MISTRAL_REALTIME_DEFAULT_SAMPLE_RATE,
